VALUES ('3c58ba73-2878-4e5a-bf4f-404f60422b41', 'A linear function $f$ satisfies $f(3) = 0$ and $f(7) = 8$. What is the value of $f(-4)$?', NULL, NULL, '[{"id":"A","text":"$-14$","is_correct":true,"explanation":"Slope $m = \\frac{8-(0)}{7-3} = 2$. Then $f(-4) = 2(-4-3)+(0) = -14$."},{"id":"B","text":"$-12$","is_correct":false,"explanation":"This adds 2 to the correct value."},{"id":"C","text":"$2$","is_correct":false,"explanation":"That is the slope, not $f(-4)$."},{"id":"D","text":"$-18$","is_correct":false,"explanation":"This subtracts 4 from the correct value."}]'::jsonb, 'A', 'Slope $m = \frac{8-(0)}{7-3} = 2$. Using point-slope from $(3, 0)$: $f(-4) = 2(-4-3)+(0) = -14$.', NULL, 'Algebra', 'Linear functions', 'math', 'algebra', 'LIF', 'LIF', 'hard', true, 'SAT', 'multiple_choice', true, true, 'scholaris_ai', '{"generator":"scholaris_template_v1","original":true,"explanation_v2":true}'::jsonb, now(), now())
